        from: {},
        to: 'src/utils.ts',
        source: {},
        target: 'src/utils.ts',
      } as unknown as FGLink,
    ],
    [
      'target',
      {
        id: 'src/app.ts->src/utils.ts',
        from: 'src/app.ts',
        to: {},
        source: 'src/app.ts',
        target: {},
      } as unknown as FGLink,
    ],
